<?php
declare(strict_types=1);

function promotional_tracking_url(string $slug): string {
    return rtrim((string)config('url'),'/').'/go/'.rawurlencode($slug);
}
function promotional_device_type(string $ua): string {
    if(preg_match('/bot|crawler|spider|preview|facebookexternalhit|slurp/i',$ua))return 'Bot';
    if(preg_match('/ipad|tablet|kindle|silk/i',$ua))return 'Tablet';
    if(preg_match('/mobile|iphone|ipod|android/i',$ua))return 'Mobile';
    return $ua===''?'Unknown':'Desktop';
}
function promotional_link_row(int $id): array {
    $stmt=db()->prepare('SELECT p.*,COALESCE(NULLIF(u.display_name,\'\'),u.username) creator FROM promotional_links p LEFT JOIN users u ON u.id=p.created_by WHERE p.id=?');
    $stmt->execute([$id]);$row=$stmt->fetch();if(!$row){http_response_code(404);exit('Promotional link not found');}return $row;
}
function promotional_slug(string $requested=''): string {
    $slug=strtolower(trim($requested));$slug=preg_replace('/[^a-z0-9_-]+/','-',$slug);$slug=trim((string)$slug,'-_');
    return $slug!==''?substr($slug,0,80):strtolower(bin2hex(random_bytes(5)));
}

// Public tracked redirect. Raw IP addresses are never stored.
if(preg_match('#^/go/([a-zA-Z0-9_-]{1,80})$#',$path,$m)&&$method==='GET'){
    $stmt=db()->prepare('SELECT * FROM promotional_links WHERE slug=? AND active=1');$stmt->execute([$m[1]]);$link=$stmt->fetch();
    if(!$link){http_response_code(404);header('Content-Type: text/plain; charset=UTF-8');exit('This promotional link is unavailable.');}
    $ua=substr((string)($_SERVER['HTTP_USER_AGENT']??''),0,1000);$ip=(string)($_SERVER['REMOTE_ADDR']??'');
    $visitor=hash_hmac('sha256',$ip.'|'.$ua,(string)config('key'));$referrer=substr((string)($_SERVER['HTTP_REFERER']??''),0,2000)?:null;
    $query=$_GET;$utm=function(string $key)use($query):?string{$raw=$query[$key]??'';$value=is_scalar($raw)?trim((string)$raw):'';return $value===''?null:mb_substr($value,0,190);};
    try{db()->prepare('INSERT INTO promotional_link_clicks(promotional_link_id,visitor_hash,referrer,user_agent,device_type,utm_source,utm_medium,utm_campaign,query_json) VALUES(?,?,?,?,?,?,?,?,?)')->execute([$link['id'],$visitor,$referrer,$ua,promotional_device_type($ua),$utm('utm_source'),$utm('utm_medium'),$utm('utm_campaign'),$query?json_encode($query):null]);}
    catch(Throwable $e){app_log('error','Promotional link analytics could not be recorded',['promotional_link_id'=>(int)$link['id'],'error'=>$e->getMessage()]);}
    $destination=$link['destination_url'];if($query){$separator=str_contains($destination,'?')?'&':'?';$destination.=$separator.http_build_query($query);}
    header('Cache-Control: no-store');header('Referrer-Policy: strict-origin-when-cross-origin');header('Location: '.$destination, true, 302);exit;
}

if($path==='/promotions/links'){
    require_permission('promotional_links.view');
    if($method==='POST'){
        require_permission('promotional_links.edit');verify_csrf();$action=(string)post('action');$id=(int)post('link_id');$link=promotional_link_row($id);
        if($action==='toggle'){db()->prepare('UPDATE promotional_links SET active=?,updated_by=? WHERE id=?')->execute([$link['active']?0:1,user()['id'],$id]);audit($link['active']?'deactivate':'activate','promotional_link',$id);flash('success','Promotional link status updated.');}
        redirect('/promotions/links');
    }
    $rows=db()->query("SELECT p.*,COUNT(c.id) clicks,COUNT(DISTINCT c.visitor_hash) unique_visitors,MAX(c.clicked_at) last_click FROM promotional_links p LEFT JOIN promotional_link_clicks c ON c.promotional_link_id=p.id GROUP BY p.id ORDER BY p.created_at DESC")->fetchAll();
    layout('Promotional links',function()use($rows){?><div class="actions"><h1 style="margin:0">Promotional links</h1><span class="spacer"></span><a class="btn secondary" href="/promotions/links/stats">View all analytics</a><?php if(can('events.edit')):?><a class="btn" href="/promotions/links/new">Create link / QR code</a><?php endif?></div><div class="card"><p class="muted">Each tracked URL remains stable when its destination changes, so printed QR codes can be reused.</p><div style="overflow:auto"><table><thead><tr><th>Name</th><th>Tracked URL</th><th>Clicks</th><th>Unique</th><th>Last click</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach($rows as $row):$url=promotional_tracking_url($row['slug']);?><tr><td><strong><?=e($row['name'])?></strong><br><span class="muted"><?=e($row['destination_url'])?></span></td><td><a href="<?=e($url)?>" target="_blank" rel="noopener"><?=e($url)?></a></td><td><?=number_format((int)$row['clicks'])?></td><td><?=number_format((int)$row['unique_visitors'])?></td><td><?=e($row['last_click']?:'—')?></td><td><?=$row['active']?'Active':'Inactive'?></td><td><div class="actions"><a class="btn compact secondary" href="/promotions/links/<?=$row['id']?>/stats">Stats / QR</a><?php if(can('events.edit')):?><a class="btn compact" href="/promotions/links/<?=$row['id']?>/edit">Edit</a><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="link_id" value="<?=$row['id']?>"><button class="compact <?=$row['active']?'danger':'secondary'?>" name="action" value="toggle"><?=$row['active']?'Disable':'Enable'?></button></form><?php endif?></div></td></tr><?php endforeach?></tbody></table></div><?php if(!$rows):?><p>No promotional links have been created yet.</p><?php endif?></div><?php });exit;
}

if($path==='/promotions/links/new'||preg_match('#^/promotions/links/(\d+)/edit$#',$path,$m)){
    require_permission('promotional_links.edit');$id=isset($m[1])?(int)$m[1]:null;$link=$id?promotional_link_row($id):[];
    if($method==='POST'){
        verify_csrf();$name=trim((string)post('name'));$destination=trim((string)post('destination_url'));$slug=promotional_slug((string)post('slug'));
        $parts=parse_url($destination);if($name===''||!filter_var($destination,FILTER_VALIDATE_URL)||!in_array(strtolower((string)($parts['scheme']??'')),['http','https'],true)){flash('error','Enter a name and a valid HTTP or HTTPS destination URL.');}
        else try{$duplicate=db()->prepare('SELECT id,name,slug,campaign_name,channel,variant FROM promotional_links WHERE destination_url=? AND id<>? ORDER BY created_at DESC');$duplicate->execute([$destination,$id?:0]);$matches=$duplicate->fetchAll();if($matches&&!post('confirm_duplicate')){layout('Confirm duplicate destination',function()use($matches){?><h1>Similar promotional links already exist</h1><div class="card"><p>This is allowed and is useful for tracking separate channels, posts, or campaign days. Confirm that you want another tracked link to the same destination.</p><table><thead><tr><th>Name</th><th>Campaign</th><th>Channel</th><th>Variant</th></tr></thead><tbody><?php foreach($matches as $match):?><tr><td><?=e($match['name'])?></td><td><?=e($match['campaign_name']?:'—')?></td><td><?=e($match['channel']?:'—')?></td><td><?=e($match['variant']?:'—')?></td></tr><?php endforeach?></tbody></table><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><?php foreach($_POST as $key=>$value)if($key!=='_csrf'&&!is_array($value)):?><input type="hidden" name="<?=e((string)$key)?>" value="<?=e((string)$value)?>"><?php endif?><button name="confirm_duplicate" value="1">Create separate tracked link</button> <a class="btn secondary" href="/promotions/links">Cancel</a></form></div><?php });exit;} $campaign=trim((string)post('campaign_name'));$channel=trim((string)post('channel'));$variant=trim((string)post('variant'));if($id){db()->prepare('UPDATE promotional_links SET name=?,slug=?,destination_url=?,campaign_name=?,channel=?,variant=?,active=?,updated_by=? WHERE id=?')->execute([$name,$slug,$destination,$campaign?:null,$channel?:null,$variant?:null,post('active')?1:0,user()['id'],$id]);audit('update','promotional_link',$id,['slug'=>$slug,'campaign'=>$campaign,'channel'=>$channel,'variant'=>$variant]);}else{db()->prepare('INSERT INTO promotional_links(name,slug,destination_url,campaign_name,channel,variant,active,created_by,updated_by) VALUES(?,?,?,?,?,?,?,?,?)')->execute([$name,$slug,$destination,$campaign?:null,$channel?:null,$variant?:null,1,user()['id'],user()['id']]);$id=(int)db()->lastInsertId();audit('create','promotional_link',$id,['slug'=>$slug,'campaign'=>$campaign,'channel'=>$channel,'variant'=>$variant]);}flash('success','Promotional link saved.');redirect('/promotions/links/'.$id.'/stats');}catch(PDOException $e){if(($e->errorInfo[1]??0)===1062)flash('error','That short code is already in use. Choose another.');else throw $e;}
    }
    layout($id?'Edit promotional link':'Create promotional link',function()use($link,$id){?><div class="actions"><h1 style="margin:0"><?=$id?'Edit promotional link':'Create promotional link / QR code'?></h1><span class="spacer"></span><a class="btn secondary" href="/promotions/links">Back to links</a></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Name<input name="name" value="<?=e($link['name']??'')?>" placeholder="LinkedIn message - Day 1" required maxlength="190"></label><label>Short code<input name="slug" value="<?=e($link['slug']??'')?>" placeholder="Leave blank to generate automatically" maxlength="80" pattern="[A-Za-z0-9_-]+"><span class="muted">Letters, numbers, underscores, and hyphens.</span></label><label class="full">Destination URL<input type="url" name="destination_url" value="<?=e($link['destination_url']??'')?>" placeholder="https://example.com/landing-page" required maxlength="2000"></label><label>Campaign<input name="campaign_name" value="<?=e($link['campaign_name']??'')?>" placeholder="Five-day outreach"></label><label>Channel<input name="channel" value="<?=e($link['channel']??'')?>" placeholder="LinkedIn, Instagram, email…"></label><label>Variant / touchpoint<input name="variant" value="<?=e($link['variant']??'')?>" placeholder="Day 1, Post A, Message 2…"></label><?php if($id):?><label><input style="width:auto" type="checkbox" name="active" value="1" <?=$link['active']?'checked':''?>> Active</label><?php endif?></div><p class="muted">Multiple links may point to the same destination. Use campaign, channel, and variant to compare their performance.</p><button>Save and generate QR code</button></form><?php });exit;
}

if($path==='/promotions/links/stats'){
    require_permission('promotional_links.view');
    $totals=db()->query("SELECT COUNT(*) clicks,COUNT(DISTINCT visitor_hash) unique_visitors,SUM(clicked_at>=CURRENT_DATE) today,SUM(clicked_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)) last_30 FROM promotional_link_clicks")->fetch();
    $groups=db()->query("SELECT COALESCE(NULLIF(p.campaign_name,''),'Unassigned') campaign,COALESCE(NULLIF(p.channel,''),'Unassigned') channel,COUNT(DISTINCT p.id) links,COUNT(c.id) clicks,COUNT(DISTINCT c.visitor_hash) unique_visitors,SUM(c.clicked_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)) last_30 FROM promotional_links p LEFT JOIN promotional_link_clicks c ON c.promotional_link_id=p.id GROUP BY campaign,channel ORDER BY clicks DESC,campaign,channel")->fetchAll();
    $rows=db()->query("SELECT p.id,p.name,p.slug,p.destination_url,p.campaign_name,p.channel,p.variant,p.active,COUNT(c.id) clicks,COUNT(DISTINCT c.visitor_hash) unique_visitors,SUM(c.clicked_at>=CURRENT_DATE) today,MAX(c.clicked_at) last_click FROM promotional_links p LEFT JOIN promotional_link_clicks c ON c.promotional_link_id=p.id GROUP BY p.id ORDER BY clicks DESC,p.name")->fetchAll();
    layout('Promotional link analytics',function()use($rows,$groups,$totals){?><div class="actions"><h1 style="margin:0">Promotional link analytics</h1><span class="spacer"></span><a class="btn secondary" href="/promotions/links">Manage links</a></div><div class="grid analytics-metrics"><div class="card"><div class="metric"><?=number_format((int)$totals['clicks'])?></div>Total clicks</div><div class="card"><div class="metric"><?=number_format((int)$totals['unique_visitors'])?></div>Unique visitors</div><div class="card"><div class="metric"><?=number_format((int)$totals['last_30'])?></div>Clicks in 30 days</div><div class="card"><div class="metric"><?=number_format((int)$totals['today'])?></div>Today</div></div><div class="card"><h2>Campaign and channel performance</h2><table><thead><tr><th>Campaign</th><th>Channel</th><th>Tracked links</th><th>Clicks</th><th>Unique</th><th>Last 30 days</th></tr></thead><tbody><?php foreach($groups as $group):?><tr><td><?=e($group['campaign'])?></td><td><?=e($group['channel'])?></td><td><?=number_format((int)$group['links'])?></td><td><?=number_format((int)$group['clicks'])?></td><td><?=number_format((int)$group['unique_visitors'])?></td><td><?=number_format((int)$group['last_30'])?></td></tr><?php endforeach?></tbody></table></div><div class="card"><h2>Individual link and variant performance</h2><table><thead><tr><th>Link</th><th>Campaign</th><th>Channel</th><th>Variant</th><th>Clicks</th><th>Unique</th><th>Today</th></tr></thead><tbody><?php foreach($rows as $row):?><tr><td><a href="/promotions/links/<?=$row['id']?>/stats"><?=e($row['name'])?></a><br><span class="muted"><?=e($row['destination_url'])?></span></td><td><?=e($row['campaign_name']?:'—')?></td><td><?=e($row['channel']?:'—')?></td><td><?=e($row['variant']?:'—')?></td><td><?=number_format((int)$row['clicks'])?></td><td><?=number_format((int)$row['unique_visitors'])?></td><td><?=number_format((int)$row['today'])?></td></tr><?php endforeach?></tbody></table></div><?php });exit;
}

