if(preg_match('#^/promotions/links/(\d+)/stats$#',$path,$m)){
    require_permission('promotional_links.view');$id=(int)$m[1];$link=promotional_link_row($id);$url=promotional_tracking_url($link['slug']);
    $stmt=db()->prepare("SELECT COUNT(*) clicks,COUNT(DISTINCT visitor_hash) unique_visitors,SUM(clicked_at>=CURRENT_DATE) today,SUM(clicked_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)) last_30 FROM promotional_link_clicks WHERE promotional_link_id=?");$stmt->execute([$id]);$totals=$stmt->fetch();
    $stmt=db()->prepare("SELECT DATE(clicked_at) day,COUNT(*) clicks,COUNT(DISTINCT visitor_hash) unique_visitors FROM promotional_link_clicks WHERE promotional_link_id=? AND clicked_at>=DATE_SUB(CURRENT_DATE,INTERVAL 29 DAY) GROUP BY DATE(clicked_at) ORDER BY day");$stmt->execute([$id]);$daily=$stmt->fetchAll();
    $dimension=function(string $column)use($id):array{$allowed=['device_type','referrer','utm_source','utm_medium','utm_campaign'];if(!in_array($column,$allowed,true))return [];$stmt=db()->prepare("SELECT COALESCE(NULLIF($column,''),'Direct / Not set') label,COUNT(*) clicks FROM promotional_link_clicks WHERE promotional_link_id=? GROUP BY $column ORDER BY clicks DESC LIMIT 12");$stmt->execute([$id]);return $stmt->fetchAll();};
    $devices=$dimension('device_type');$sources=$dimension('utm_source');$referrers=$dimension('referrer');
    layout($link['name'].' analytics',function()use($link,$url,$totals,$daily,$devices,$sources,$referrers){?><div class="actions"><h1 style="margin:0"><?=e($link['name'])?> analytics</h1><span class="spacer"></span><?php if(can('events.edit')):?><a class="btn" href="/promotions/links/<?=$link['id']?>/edit">Edit destination</a><?php endif?><a class="btn secondary" href="/promotions/links/stats">All analytics</a></div><div class="card qr-panel"><div id="qr-code" class="qr-code"></div><div style="flex:1;min-width:260px"><h2>Tracked URL</h2><div class="promo-url"><input id="tracked-url" readonly value="<?=e($url)?>"><button type="button" id="copy-url">Copy</button></div><p><strong>Destination:</strong> <a href="<?=e($link['destination_url'])?>" target="_blank" rel="noopener"><?=e($link['destination_url'])?></a></p><button type="button" class="secondary" id="download-qr">Download QR code</button></div></div><div class="grid analytics-metrics"><div class="card"><div class="metric"><?=number_format((int)$totals['clicks'])?></div>Total clicks</div><div class="card"><div class="metric"><?=number_format((int)$totals['unique_visitors'])?></div>Approx. unique visitors</div><div class="card"><div class="metric"><?=number_format((int)$totals['today'])?></div>Today</div><div class="card"><div class="metric"><?=number_format((int)$totals['last_30'])?></div>Last 30 days</div></div><div class="card"><h2>Last 30 days</h2><div class="chart-wrap"><canvas id="click-chart"></canvas></div></div><div class="grid"><div class="card"><h2>Devices</h2><?php foreach($devices as $row):?><p><?=e($row['label'])?> <strong style="float:right"><?=number_format((int)$row['clicks'])?></strong></p><?php endforeach?></div><div class="card"><h2>UTM sources</h2><?php foreach($sources as $row):?><p><?=e($row['label'])?> <strong style="float:right"><?=number_format((int)$row['clicks'])?></strong></p><?php endforeach?></div><div class="card"><h2>Top referrers</h2><?php foreach($referrers as $row):?><p style="overflow-wrap:anywhere"><?=e($row['label'])?> <strong style="float:right"><?=number_format((int)$row['clicks'])?></strong></p><?php endforeach?></div></div><script src="https://cdn.jsdelivr.net/npm/qrcodejs@1.0.0/qrcode.min.js"></script><script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.7/dist/chart.umd.min.js"></script><script>const tracked=<?=json_encode($url,JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_AMP|JSON_HEX_QUOT)?>;new QRCode(document.querySelector('#qr-code'),{text:tracked,width:220,height:220,correctLevel:QRCode.CorrectLevel.H});document.querySelector('#copy-url').onclick=async()=>{await navigator.clipboard.writeText(tracked);document.querySelector('#copy-url').textContent='Copied'};document.querySelector('#download-qr').onclick=()=>{const source=document.querySelector('#qr-code canvas')||document.querySelector('#qr-code img'),a=document.createElement('a');a.download=<?=json_encode($link['slug'].'-qr.png')?>;a.href=source.tagName==='CANVAS'?source.toDataURL('image/png'):source.src;a.click()};new Chart(document.querySelector('#click-chart'),{type:'line',data:{labels:<?=json_encode(array_column($daily,'day'))?>,datasets:[{label:'Clicks',data:<?=json_encode(array_map('intval',array_column($daily,'clicks')))?>,borderColor:getComputedStyle(document.documentElement).getPropertyValue('--primary'),tension:.2},{label:'Unique visitors',data:<?=json_encode(array_map('intval',array_column($daily,'unique_visitors')))?>,borderColor:getComputedStyle(document.documentElement).getPropertyValue('--accent'),tension:.2}]},options:{responsive:true,maintainAspectRatio:false,scales:{y:{beginAtZero:true,ticks:{precision:0}}}}})</script><?php });exit;
}
